children.data-bind:
css: {
        'animate': animate() && animate.animateBanner(),
        'slide-out-next': animate.isSlideOutNext(),
        'slide-in-next': animate.isSlideInNext(),
        'slide-out-back': animate.isSlideOutBack(),
        'slide-in-back': animate.isSlideInBack() }

component: { name: 'identity-banner-control',
            params: {
                userTileUrl: svr.urlProfilePhoto,
                displayName: sharedData.displayName || svr.sPOST_Username,
                isBackButtonVisible: isBackButtonVisible(),
                focusOnBackButton: isBackButtonFocused(),
                backButtonDescribedBy: backButtonDescribedBy() },
            event: {
                backButtonClick: identityBanner_onBackButtonClick } }

pageViewComponent: { name: 'kmsi-view',
                params: {
                    serverData: svr,
                    displayName: sharedData.displayName },
                event: {
                    submitReady: $kmsiPage.view_onSubmitReady } }

component: { name: 'footer-buttons-field',
        params: {
            serverData: svr,
            primaryButtonText: str['STR_Kmsi_Accept_Kmsi'],
            secondaryButtonText: str['STR_Kmsi_Decline_Kmsi'],
            focusOnPrimaryButton: true,
            primaryButtonDescribedBy: 'KmsiDescription' },
        event: {
            primaryButtonClick: primaryButton_onClick,
            secondaryButtonClick: secondaryButton_onClick } }

visible: isPrimaryButtonVisible() || isSecondaryButtonVisible(),
css: { 'no-margin-bottom': removeBottomMargin },
externalCss: { 'button-field-container': true }

htmlWithMods: tenantBranding.BoilerPlateText,
htmlMods: { filterLinks: svr.fIsHosted },
css: { 'transparent-lightbox': tenantBranding.UseTransparentLightBox }

component: { name: 'instrumentation-control',
            publicMethods: instrumentationMethods,
            params: { serverData: svr } }

externalCss: {
    'footer': true,
    'has-background': !$page.useDefaultBackground() && $page.showFooter(),
    'background-always-visible': $page.backgroundLogoUrl }
